const glass=(T)=>({background:T.card,border:`1px solid ${T.border}`,borderRadius:16,padding:20,transition:"all .2s"});
const lbl=(T)=>({fontSize:10,color:T.textDim,letterSpacing:1.5,textTransform:"uppercase",fontWeight:700,marginBottom:6});
const pill=(bg,color)=>({display:"inline-flex",alignItems:"center",gap:3,padding:"3px 8px",borderRadius:20,fontSize:10,fontWeight:600,background:bg,color});
const btnS=(T,pri)=>({padding:"8px 14px",borderRadius:10,border:pri?"none":`1px solid ${T.border}`,background:pri?T.success:"transparent",color:pri?"#080c18":T.text,fontWeight:700,fontSize:11,cursor:"pointer",display:"flex",alignItems:"center",gap:5,transition:"all .15s"});
const inpS=(T)=>({background:T.bg,border:`1px solid ${T.border}`,borderRadius:10,padding:"10px 14px",color:T.text,fontSize:13,width:"100%",outline:"none",boxSizing:"border-box",fontFamily:"inherit"});

