function PBar({pct,color,height=6,bg}){return(<div style={{width:"100%",height,borderRadius:height,background:bg||"rgba(255,255,255,.06)",overflow:"hidden"}}><div style={{width:`${Math.min(Math.max(pct,0),100)}%`,height:"100%",borderRadius:height,background:color,transition:"width .8s cubic-bezier(.4,0,.2,1)"}}/></div>)}

function StatCard({title,value,change,icon:Icon,color,T,delay=0,subtitle}){
return(<div style={{...glass(T),animation:`fadeUp .5s ease ${delay}s both`}}>
<div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
<div><div style={lbl(T)}>{title}</div>
<div style={{fontSize:28,fontWeight:800,letterSpacing:-1.5,fontFamily:"'Space Mono',monospace",color:color||T.success}}>{value}</div>
{change!==undefined&&<div style={pill(change>=0?T.successBg:T.dangerBg,change>=0?T.success:T.danger)}>{change>=0?<ArrowUpRight size={10}/>:<ArrowDownRight size={10}/>}{Math.abs(change).toFixed(1)}%</div>}
{subtitle&&<div style={{fontSize:11,color:T.textMuted,marginTop:4}}>{subtitle}</div>}</div>
<div style={{padding:10,borderRadius:12,background:`linear-gradient(135deg,${(color||T.success)}15,${(color||T.success)}05)`}}><Icon size={18} color={color||T.success}/></div>
</div></div>)}

function Modal({children,onClose,T}){return(
<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.65)",backdropFilter:"blur(8px)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}} onClick={onClose}>
<div style={{background:T.card,borderRadius:20,border:`1px solid ${T.border}`,padding:28,width:520,maxWidth:"94vw",maxHeight:"88vh",overflow:"auto",animation:"fadeUp .3s ease"}} onClick={e=>e.stopPropagation()}>{children}</div></div>)}

function Confetti({show}){if(!show)return null;return(<div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:200}}><style>{`@keyframes cf{0%{transform:translateY(-10vh) rotate(0);opacity:1}100%{transform:translateY(110vh) rotate(720deg);opacity:0}}`}</style>{Array.from({length:30},(_,i)=><div key={i} style={{position:"absolute",left:Math.random()*100+"%",top:0,width:4+Math.random()*5,height:6+Math.random()*7,background:CHART_COLORS[i%6],borderRadius:2,animation:`cf ${1+Math.random()*1.5}s ease-in ${Math.random()*.4}s forwards`}}/>)}</div>)}

